import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"ToS 경고: 계정 리스크와 보안 실천 방법 | Antigravity Auth","description":"Antigravity Auth 플러그인 사용 리스크와 계정 보안 실천 방법을 배우세요. 고위험 시나리오, 쉐도우 밴 메커니즘과 속도 제한의 차이점을 이해하고, 다중 계정 전략, 사용량 제어, 계정 워밍업 방법을 익히세요.","frontmatter":{"title":"ToS 경고: 계정 리스크와 보안 실천 방법 | Antigravity Auth","sidebarTitle":"계정 정지 당하지 않기","subtitle":"ToS 경고: 계정 리스크와 보안 실천 방법","description":"Antigravity Auth 플러그인 사용 리스크와 계정 보안 실천 방법을 배우세요. 고위험 시나리오, 쉐도우 밴 메커니즘과 속도 제한의 차이점을 이해하고, 다중 계정 전략, 사용량 제어, 계정 워밍업 방법을 익히세요.","tags":["FAQ","리스크 경고","계정 보안"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"ko/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"ko/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),e={name:"ko/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function r(n,l,s,d,h,g){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="tos-경고" tabindex="-1">ToS 경고 <a class="header-anchor" href="#tos-경고" aria-label="Permalink to &quot;ToS 경고&quot;">​</a></h1><p>이 과정을 마치면 Antigravity Auth 플러그인 사용으로 발생할 수 있는 리스크를 이해하고 Google 계정을 안전하게 보호하는 방법을 알 수 있습니다.</p><h2 id="지금-당신의-고민" tabindex="-1">지금 당신의 고민 <a class="header-anchor" href="#지금-당신의-고민" aria-label="Permalink to &quot;지금 당신의 고민&quot;">​</a></h2><p>Antigravity Auth 플러그인을 사용해 Google Antigravity의 AI 모델에 접근하는 것을 고려 중이지만 몇 가지 우려가 있습니다:</p><ul><li>커뮤니티에서 계정 정지나 쉐도우 밴을 당했다는 보고를 봤다</li><li>비공식 도구 사용이 Google의 서비스 약관을 위반하는지 걱정된다</li><li>새 계정을 사용해야 할지 오래된 계정을 사용해야 할지 확실하지 않다</li><li>리스크를 낮추는 방법이 궁금하다</li></ul><p>이러한 우려는 타당합니다. 비공식 도구를 사용하는 것에는 항상 일정한 리스크가 따르며, 본 문서는 구체적인 리스크 포인트와 대응 전략을 안내합니다.</p><h2 id="이-과정이-필요한-경우" tabindex="-1">이 과정이 필요한 경우 <a class="header-anchor" href="#이-과정이-필요한-경우" aria-label="Permalink to &quot;이 과정이 필요한 경우&quot;">​</a></h2><ul><li><strong>플러그인 설치 전</strong>: 리스크를 이해한 후 사용 여부를 결정할 때</li><li><strong>계정 선택 시</strong>: 어떤 Google 계정으로 인증할지 결정할 때</li><li><strong>정지를 당했을 때</strong>: 가능한 원인과 예방 조치를 이해할 때</li><li><strong>새로운 사용자 등록 시</strong>: 고위험 조작 패턴을 피할 때</li></ul><hr><h2 id="핵심-리스크-개요" tabindex="-1">핵심 리스크 개요 <a class="header-anchor" href="#핵심-리스크-개요" aria-label="Permalink to &quot;핵심 리스크 개요&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">중요 경고</p><p><strong>이 플러그인을 사용하면 Google의 서비스 약관(Terms of Service)을 위반할 수 있습니다.</strong></p><p>일부 사용자들은 Google 계정이 정지되거나 쉐도우 밴(Shadow Ban, 명확한 알림 없이 접근 제한)되었다고 보고했습니다.</p><p><strong>이 플러그인을 사용하는 것은 다음 선언에 동의함을 의미합니다:</strong></p><ol><li>이것은 비공식 도구이며 Google의 인가나 보증을 받지 않았습니다</li><li>Google 계정이 일시 정지되거나 영구 정지될 수 있습니다</li><li>이 플러그인 사용의 모든 리스크와 결과는 본인이 부담합니다</li></ol></div><h3 id="쉐도우-밴이란" tabindex="-1">쉐도우 밴이란? <a class="header-anchor" href="#쉐도우-밴이란" aria-label="Permalink to &quot;쉐도우 밴이란?&quot;">​</a></h3><p>**쉐도우 밴(Shadow Ban)**은 Google이 의심스러운 계정에 취하는 제한 조치입니다. 직접적인 정지와 달리 쉐도우 밴은 명확한 오류 메시지를 표시하지 않고:</p><ul><li>API 요청이 403 또는 429 오류를 반환합니다</li><li>할당량은 표시되지만 실제로 호출할 수 없습니다</li><li>다른 계정은 정상적으로 작동하고, 표시된 계정만 영향을 받습니다</li></ul><p>쉐도우 밴은 보통 상당히 오래 지속됩니다(며칠에서 몇 주), 이의 신청으로 복구할 수 없습니다.</p><hr><h2 id="고위험-시나리오" tabindex="-1">고위험 시나리오 <a class="header-anchor" href="#고위험-시나리오" aria-label="Permalink to &quot;고위험 시나리오&quot;">​</a></h2><p>다음 시나리오는 계정이 표시되거나 정지될 리스크를 크게 높입니다:</p><h3 id="🚨-시나리오-1-완전히-새로운-google-계정" tabindex="-1">🚨 시나리오 1: 완전히 새로운 Google 계정 <a class="header-anchor" href="#🚨-시나리오-1-완전히-새로운-google-계정" aria-label="Permalink to &quot;🚨 시나리오 1: 완전히 새로운 Google 계정&quot;">​</a></h3><p><strong>위험 등급: 매우 높음</strong></p><p>새로 등록된 Google 계정으로 이 플러그인을 사용하면 정지될 확률이 매우 높습니다. 이유:</p><ul><li>새 계정은 역사적 행동 데이터가 부족해 Google의 남용 감지 시스템에 표시되기 쉽습니다</li><li>새 계정에서의 다량의 API 호출은 비정상적 행동으로 간주됩니다</li><li>Google은 새 계정에 대한 심사를 더 엄격하게 합니다</li></ul><p><strong>권장 사항</strong>: 이 플러그인을 위해 새 계정을 만들지 마세요.</p><h3 id="🚨-시나리오-2-새-계정-pro-ultra-구독" tabindex="-1">🚨 시나리오 2: 새 계정 + Pro/Ultra 구독 <a class="header-anchor" href="#🚨-시나리오-2-새-계정-pro-ultra-구독" aria-label="Permalink to &quot;🚨 시나리오 2: 새 계정 + Pro/Ultra 구독&quot;">​</a></h3><p><strong>위험 등급: 매우 높음</strong></p><p>새로 등록한 계정에 즉시 Google의 Pro 또는 Ultra 서비스를 구독하면 종종 표시되고 정지됩니다. 이유:</p><ul><li>구독 후의 높은 사용량 패턴이 새 계정에서는 남용처럼 보입니다</li><li>Google은 새로운 유료 사용자에 대한 심사를 더 엄격하게 합니다</li><li>이 패턴은 정상 사용자의 성장 경로와 너무 다릅니다</li></ul><p><strong>권장 사항</strong>: 계정이 &quot;자연 성장&quot;할 수 있도록 시간을 주세요(최소 몇 개월), 구독을 고려하기 전에.</p><h3 id="🟡-시나리오-3-짧은-시간-내에-다량의-요청" tabindex="-1">🟡 시나리오 3: 짧은 시간 내에 다량의 요청 <a class="header-anchor" href="#🟡-시나리오-3-짧은-시간-내에-다량의-요청" aria-label="Permalink to &quot;🟡 시나리오 3: 짧은 시간 내에 다량의 요청&quot;">​</a></h3><p><strong>위험 등급: 높음</strong></p><p>짧은 시간 내에 다량의 API 요청을 하거나, 자주 병렬 에이전트/다중 세션을 사용하면 속도 제한과 남용 감지가 트리거됩니다. 이유:</p><ul><li>OpenCode의 요청 패턴은 기본 앱보다 더 집중적입니다(도구 호출, 재시도, 스트리밍 등)</li><li>높은 동시 요청은 Google의 보호 메커니즘을 트리거합니다</li></ul><p><strong>권장 사항</strong>:</p><ul><li>요청 빈도와 동시성을 제어하세요</li><li>여러 병렬 에이전트를 동시에 시작하는 것을 피하세요</li><li>다중 계정 순환으로 요청을 분산하세요</li></ul><h3 id="🟡-시나리오-4-유일한-google-계정-사용" tabindex="-1">🟡 시나리오 4: 유일한 Google 계정 사용 <a class="header-anchor" href="#🟡-시나리오-4-유일한-google-계정-사용" aria-label="Permalink to &quot;🟡 시나리오 4: 유일한 Google 계정 사용&quot;">​</a></h3><p><strong>위험 등급: 중간</strong></p><p>Google 계정이 하나뿐이고, Gmail, Drive 등 핵심 서비스에 의존하는 경우 위험이 높습니다. 이유:</p><ul><li>계정이 정지되면 일상 업무에 영향을 줍니다</li><li>이의 신청으로 복구할 수 없습니다</li><li>대체 계획이 없습니다</li></ul><p><strong>권장 사항</strong>: 핵심 서비스에 의존하지 않는 별도의 계정을 사용하세요.</p><hr><h2 id="최적의-실천-권장-사항" tabindex="-1">최적의 실천 권장 사항 <a class="header-anchor" href="#최적의-실천-권장-사항" aria-label="Permalink to &quot;최적의 실천 권장 사항&quot;">​</a></h2><h3 id="✅-권장-사항" tabindex="-1">✅ 권장 사항 <a class="header-anchor" href="#✅-권장-사항" aria-label="Permalink to &quot;✅ 권장 사항&quot;">​</a></h3><p><strong>1. 확립된 Google 계정 사용</strong></p><p>일정 기간(6개월 이상 권장) 사용해 온 Google 계정을 우선적으로 선택하세요:</p><ul><li>정상적인 Google 서비스 사용 이력이 있습니다(Gmail, Drive, Google 검색 등)</li><li>과거 위반 기록이 없습니다</li><li>휴대폰 번호가 연결되어 검증이 완료되었습니다</li></ul><p><strong>2. 다중 계정 구성</strong></p><p>여러 Google 계정을 추가하여 순환으로 요청을 분산하세요:</p><ul><li>최소 2-3개 계정을 구성하세요</li><li><code>account_selection_strategy: &quot;hybrid&quot;</code> 전략(기본값)을 사용하세요</li><li>속도 제한을 만나면 자동으로 계정을 전환합니다</li></ul><p><strong>3. 사용량 제어</strong></p><ul><li>짧은 시간 내에 집중적인 요청을 피하세요</li><li>병렬 에이전트의 수를 줄이세요</li><li><code>antigravity.json</code>에서 <code>max_rate_limit_wait_seconds: 0</code>을 설정하여 재시도 대신 빠르게 실패하세요</li></ul><p><strong>4. 계정 상태 모니터링</strong></p><p>정기적으로 계정 상태를 점검하세요:</p><ul><li><code>~/.config/opencode/antigravity-accounts.json</code>의 <code>rateLimitResetTimes</code>를 확인하세요</li><li>디버그 로그 활성화: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>403/429 오류를 만나면 24-48시간 사용을 중지하세요</li></ul><p><strong>5. 먼저 공식 인터페이스에서 &quot;워밍업&quot;</strong></p><p>커뮤니티 사용자가 보고한 효과적인 방법:</p><ol><li>브라우저에서 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>에 로그인하세요</li><li>몇 가지 간단한 프롬프트를 실행하세요(예: &quot;안녕&quot;, &quot;2+2는?&quot;)</li><li>5-10회 성공 호출 후 플러그인 사용을 시작하세요</li></ol><p><strong>원리</strong>: 공식 인터페이스를 통해 계정을 사용하면 Google이 이를 정상 사용자 행동으로 간주하여 표시될 위험을 낮춥니다.</p><h3 id="❌-피해야-할-것" tabindex="-1">❌ 피해야 할 것 <a class="header-anchor" href="#❌-피해야-할-것" aria-label="Permalink to &quot;❌ 피해야 할 것&quot;">​</a></h3><ul><li>❌ 이 플러그인 전용으로 새 Google 계정 만들기</li><li>❌ 새로 등록한 계정에 즉시 Pro/Ultra 구독하기</li><li>❌ 유일한 핵심 서비스 계정(예: 업무 이메일) 사용하기</li><li>❌ 429 제한 트리거 후 반복 재시도하기</li><li>❌ 동시에 다량의 병렬 에이전트 시작하기</li><li>❌ <code>antigravity-accounts.json</code>을 버전 관리에 제출하기</li></ul><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="q-계정이-정지되면-이의-신청할-수-있나요" tabindex="-1">Q: 계정이 정지되면 이의 신청할 수 있나요? <a class="header-anchor" href="#q-계정이-정지되면-이의-신청할-수-있나요" aria-label="Permalink to &quot;Q: 계정이 정지되면 이의 신청할 수 있나요?&quot;">​</a></h3><p><strong>A: 아니요.</strong></p><p>이 플러그인으로 Google의 남용 감지가 트리거되어 정지되거나 쉐도우 밴이 된 경우, 일반적으로 이의 신청으로 복구할 수 없습니다. 이유:</p><ul><li>정지는 API 사용 패턴을 기반으로 자동 트리거됩니다</li><li>Google은 비공식 도구 사용에 엄격한 입장을 취합니다</li><li>이의 신청 시 도구 사용 목적을 설명해야 하지만, 이 플러그인 자체가 위반으로 간주될 수 있습니다</li></ul><p><strong>권장 사항</strong>:</p><ul><li>영향받지 않은 다른 계정 사용하기</li><li>모든 계정이 정지된 경우 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>를 직접 사용하기</li><li>정지된 계정에서 계속 시도하는 것 피하기</li></ul><h3 id="q-이-플러그인을-사용하면-반드시-정지되나요" tabindex="-1">Q: 이 플러그인을 사용하면 반드시 정지되나요? <a class="header-anchor" href="#q-이-플러그인을-사용하면-반드시-정지되나요" aria-label="Permalink to &quot;Q: 이 플러그인을 사용하면 반드시 정지되나요?&quot;">​</a></h3><p><strong>A: 아니요.</strong></p><p>대부분의 사용자는 이 플러그인 사용에 문제가 없습니다. 리스크는 다음에 따라 다릅니다:</p><ul><li>계정 연령과 과거 행동</li><li>사용 빈도와 요청 패턴</li><li>최적의 실천 방법 준수 여부</li></ul><p><strong>리스크 평가</strong>:</p><ul><li>오래된 계정 + 적절한 사용 + 다중 계정 순환 → 낮은 리스크</li><li>새 계정 + 집중적 요청 + 단일 계정 → 높은 리스크</li></ul><h3 id="q-쉐도우-밴과-속도-제한의-차이점은-무엇인가요" tabindex="-1">Q: 쉐도우 밴과 속도 제한의 차이점은 무엇인가요? <a class="header-anchor" href="#q-쉐도우-밴과-속도-제한의-차이점은-무엇인가요" aria-label="Permalink to &quot;Q: 쉐도우 밴과 속도 제한의 차이점은 무엇인가요?&quot;">​</a></h3><p><strong>A: 본질이 다르며 복구 방법도 다릅니다.</strong></p><table tabindex="0"><thead><tr><th>특징</th><th>쉐도우 밴</th><th>속도 제한 (429)</th></tr></thead><tbody><tr><td>트리거 원인</td><td>남용 감지, 의심스러운 표시</td><td>요청 빈도가 할당량 초과</td></tr><tr><td>오류 코드</td><td>403 또는 조용한 실패</td><td>429 Too Many Requests</td></tr><tr><td>지속 시간</td><td>며칠에서 몇 주</td><td>몇 시간에서 하루</td></tr><tr><td>복구 방법</td><td>복구 불가, 다른 계정 필요</td><td>재설정 대기 또는 계정 전환</td></tr><tr><td>예방 가능 여부</td><td>최적의 실천 방법으로 리스크 감소</td><td>요청 빈도 제어</td></tr></tbody></table><h3 id="q-기업-google-계정을-사용할-수-있나요" tabindex="-1">Q: 기업 Google 계정을 사용할 수 있나요? <a class="header-anchor" href="#q-기업-google-계정을-사용할-수-있나요" aria-label="Permalink to &quot;Q: 기업 Google 계정을 사용할 수 있나요?&quot;">​</a></h3><p><strong>A: 권장하지 않습니다.</strong></p><p>기업 계정은 일반적으로 핵심 서비스와 데이터에 연결되어 있어 정지의 영향이 더 심각합니다. 또한:</p><ul><li>기업 계정의 심사가 더 엄격합니다</li><li>기업의 IT 정책을 위반할 수 있습니다</li><li>개인이 리스크를 감수하지만 팀에 영향을 줍니다</li></ul><p><strong>권장 사항</strong>: 개인 계정을 사용하세요.</p><h3 id="q-다중-계정으로-완전히-정지를-피할-수-있나요" tabindex="-1">Q: 다중 계정으로 완전히 정지를 피할 수 있나요? <a class="header-anchor" href="#q-다중-계정으로-완전히-정지를-피할-수-있나요" aria-label="Permalink to &quot;Q: 다중 계정으로 완전히 정지를 피할 수 있나요?&quot;">​</a></h3><p><strong>A: 완전히 피할 수는 없지만 영향을 줄일 수 있습니다.</strong></p><p>다중 계정의 역할:</p><ul><li>요청을 분산시켜 개별 계정의 제한 트리거 확률을 낮춥니다</li><li>한 계정이 정지되어도 다른 계정은 계속 사용 가능합니다</li><li>제한을 만났을 때 자동 전환하여 가용성을 높입니다</li></ul><p><strong>하지만 다중 계정은 &quot;부적&quot;이 아닙니다</strong>:</p><ul><li>모든 계정이 남용 감지를 트리거하면 전부 정지될 수 있습니다</li><li>다중 계정을 남용하여 집중적 요청을 하지 마세요</li><li>각 계정은 여전히 최적의 실천 방법을 따라야 합니다</li></ul><hr><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><p>이 과정을 읽으면 다음을 알아야 합니다:</p><ul><li>[ ] 이 플러그인 사용은 Google ToS를 위반할 수 있으며, 리스크는 본인 책임입니다</li><li>[ ] 새 계정 + Pro/Ultra 구독은 고위험 시나리오입니다</li><li>[ ] 확립된 Google 계정 사용을 권장합니다</li><li>[ ] 다중 계정을 구성하여 리스크를 분산할 수 있습니다</li><li>[ ] 계정 정지 후 이의 신청으로 복구할 수 없습니다</li><li>[ ] 요청 빈도와 사용량 제어가 중요합니다</li></ul><hr><h2 id="과정-요약" tabindex="-1">과정 요약 <a class="header-anchor" href="#과정-요약" aria-label="Permalink to &quot;과정 요약&quot;">​</a></h2><p>이 과정에서는 Antigravity Auth 플러그인 사용으로 발생할 수 있는 리스크를 다룹니다:</p><ol><li><strong>핵심 리스크</strong>: Google ToS를 위반할 수 있으며, 계정이 정지되거나 쉐도우 밴당할 수 있습니다</li><li><strong>고위험 시나리오</strong>: 새 계정, 새 계정 + 구독, 집중적 요청, 유일한 핵심 계정</li><li><strong>최적의 실천</strong>: 오래된 계정 사용, 다중 계정 구성, 사용량 제어, 상태 모니터링, 먼저 &quot;워밍업&quot;</li><li><strong>FAQ</strong>: 이의 신청 불가, 리스크는 개인마다 다름, 다중 계정은 영향 감소 가능</li></ol><p>이 플러그인을 사용하기 전에 리스크를 신중하게 평가하세요. 계정 정지의 결과를 감수할 수 없다면, <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>를 직접 사용하는 것을 권장합니다.</p><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><p>이 과정의 내용은 프로젝트 README 문서의 리스크 경고 부분(README.md:23-40)을 기반으로 하며, 구체적인 코드 구현은 포함하지 않습니다.</p><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>ToS 경고 선언</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const c=t(e,[["render",r]]);export{p as __pageData,c as default};
